export const mockSevispassScan = async (sevispassScanInput: SevispassScanInput, options?: RequestInit): Promise<SevispassScanResult> => {

  return customFetch<SevispassScanResult>(getMockSevispassScanUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(sevispassScanInput)
  }
);}





export const getMockSevispassScanMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof mockSevispassScan>>, TError,{data: BodyType<SevispassScanInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof mockSevispassScan>>, TError,{data: BodyType<SevispassScanInput>}, TContext> => {

const mutationKey = ['mockSevispassScan'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof mockSevispassScan>>, {data: BodyType<SevispassScanInput>}> = (props) => {
          const {data} = props ?? {};

          return  mockSevispassScan(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type MockSevispassScanMutationResult = NonNullable<Awaited<ReturnType<typeof mockSevispassScan>>>
    export type MockSevispassScanMutationBody = BodyType<SevispassScanInput>
    export type MockSevispassScanMutationError = ErrorType<unknown>

    /**
 * @summary Simulate SevisPass QR scan – returns mock verified identity
 */
export const useMockSevispassScan = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof mockSevispassScan>>, TError,{data: BodyType<SevispassScanInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof mockSevispassScan>>,
        TError,
        {data: BodyType<SevispassScanInput>},
        TContext
      > => {
      return useMutation(getMockSevispassScanMutationOptions(options));
    }

